function WaterIntake() {
  const [glasses, setGlasses] = React.useState(0);
  const goal = 8;
  const percent = Math.min((glasses / goal) * 100, 100);
  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
      <h3 style={{ margin: '0 0 8px 0', fontSize: 16, color: '#222' }}>Water Intake</h3>
      <div style={{ position: 'relative', width: 120, height: 120, marginBottom: 12 }}>
        <svg width="120" height="120" viewBox="0 0 120 120">
          <circle cx="60" cy="60" r="52" fill="none" stroke="#e5e7eb" strokeWidth="10" />
          <circle cx="60" cy="60" r="52" fill="none" stroke="#3b82f6" strokeWidth="10" strokeLinecap="round" strokeDasharray={`${percent * 3.27} 327`} transform="rotate(-90 60 60)" />
        </svg>
        <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column' }}>
          <span style={{ fontSize: 32 }}>💧</span>
          <span style={{ fontSize: 18, fontWeight: 700, color: '#3b82f6' }}>{glasses}</span>
          <span style={{ fontSize: 11, color: '#999' }}>/ {goal}</span>
        </div>
      </div>
      <div style={{ display: 'flex', gap: 10 }}>
        <button onClick={() => setGasses(g => Math.max(0, g - 1))} style={{ width: 44, height: 44, borderRadius: '50%', border: '1px solid #ddd', background: '#fff', fontSize: 22, cursor: 'pointer', color: '#444' }}>−</button>
        <button onClick={() => setGlasses(g => g + 1)} style={{ width: 44, height: 44, borderRadius: '50%', border: 'none', background: '#3b82f6', fontSize: 22, cursor: 'pointer', color: '#fff' }}>+</button>
        <button onClick={() => setGlasses(0)} style={{ width: 44, height: 44, borderRadius: '50%', border: '1px solid #ddd', background: '#fff', fontSize: 14, cursor: 'pointer', color: '#888' }}>↺</button>
      </div>
      <p style={{ margin: '10px 0 0 0', fontSize: 12, color: '#888' }}>{glasses >= goal ? 'Goal reached! 🎉' : `${goal - glasses} more to reach your goal`}</p>
    </div>
  );
}
render(<WaterIntake/>);
